    def dependency(user: dict = Depends(get_user_from_token)):
        user_scopes = ROLE_SCOPES.get(user["role"], [])
        if scope not in user_scopes:
            raise HTTPException(
                status_code=403,
                detail=f"Requires '{scope}' permission",
            )
        return user
    return dependency

